class Solution:
    def maxSubarraySumCircular(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        def kadane_max(arr):
            max_sum = curr_sum = arr[0]
            for num in arr[1:]:
                curr_sum = max(num, curr_sum + num)
                max_sum = max(max_sum, curr_sum)
            return max_sum

        def kadane_min(arr):
            min_sum = curr_sum = arr[0]
            for num in arr[1:]:
                curr_sum = min(num, curr_sum + num)
                min_sum = min(min_sum, curr_sum)
            return min_sum

        total_sum = sum(nums)
        max_kadane = kadane_max(nums)
        min_kadane = kadane_min(nums)

        # If all numbers are negative, return max element
        if total_sum == min_kadane:
            return max_kadane

        # Return max of: max subarray or (total - min subarray)
        return max(max_kadane, total_sum - min_kadane)
